import React from 'react';
import { useNavigate } from 'react-router-dom';

export default function Leaderboard() {
  const navigate = useNavigate();
  return (
    <div className="p-5 bg-yellow-100 min-h-screen flex flex-col items-center">
      <h1 className="text-3xl text-red-800 font-bold text-center mt-5 mb-8">Bảng Phong Thần 🏆</h1>
      <ul className="w-full max-w-md bg-white p-6 rounded-xl shadow-lg border border-yellow-300">
        <li className="py-3 border-b border-gray-100 font-bold text-yellow-600 text-xl flex justify-between"><span>🥇 Nam Quốc Sơn Hà</span> <span>1500 EXP</span></li>
        <li className="py-3 border-b border-gray-100 text-gray-700 text-lg flex justify-between"><span>🥈 Cậu Bé Cưỡi Ngựa Tre</span> <span>1200 EXP</span></li>
        <li className="py-3 text-gray-700 text-lg flex justify-between"><span>🥉 Chim Lạc Nhỏ</span> <span>900 EXP</span></li>
      </ul>
      <button onClick={() => navigate('/timeline')} className="mt-8 bg-yellow-700 text-white px-6 py-2 rounded shadow">Về Dòng Thời Gian</button>
    </div>
  );
}
